1	export type Coordinate = [number, number];
2	
3	const parseCoordinate = (cellString: string): Coordinate => {
4	  const [x, y] = cellString.split(",").map(Number);
5	  return [x, y];
6	};
7	
8	const NEIGHBOR_OFFSETS: Coordinate[] = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1]
12	];
13	
14	const formatCoordinate = (x: number, y: number): string => {
15	  return `${x},${y}`;
16	};
17	
18	const countLiveNeighbors = (cell: string, livingCells: Set<string>): number => {
19	  const [x, y] = parseCoordinate(cell);
20	  let count = 0;
21	  for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	    if (livingCells.has(formatCoordinate(x + dx, y + dy))) {
23	      count++;
24	    }
25	  }
26	  return count;
27	};
