29	/**
30	 * Computes the next generation of cells in Conway's Game of Life.
31	 *
32	 * Cells are represented as strings in the format "x,y" where x and y are integers.
33	 *
34	 * Rules applied:
35	 * - Cell with < 2 neighbors dies (underpopulation)
36	 * - Cell with 2-3 neighbors survives
37	 * - Cell with > 3 neighbors dies (overpopulation)
38	 * - Dead cell with exactly 3 neighbors becomes alive (reproduction)
39	 *
40	 * @param cells Set of living cells as coordinate strings "x,y"
41	 * @returns Set of living cells in the next generation
42	 */
43	export function nextGeneration(cells: Set<string>): Set<string> {
44	  if (cells.size === 0) {
45	    return new Set();
46	  }
47	
48	  const cellsToCheck = new Set<string>();
49	
50	  // Add all living cells and their neighbors to check
51	  for (const cell of cells) {
52	    const [x, y] = parseCoordinate(cell);
53	    cellsToCheck.add(cell);
54	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
55	      cellsToCheck.add(formatCoordinate(x + dx, y + dy));
56	    }
57	  }
58	
59	  const nextGen = new Set<string>();
60	
61	  // Check each cell and determine if it survives or is born
62	  for (const cell of cellsToCheck) {
63	    const liveNeighborCount = countLiveNeighbors(cell, cells);
64	    const isAlive = cells.has(cell);
65	
66	    // Apply Game of Life rules
67	    if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
68	      nextGen.add(cell);
69	    } else if (!isAlive && liveNeighborCount === 3) {
70	      nextGen.add(cell);
71	    }
72	  }
73	
74	  return nextGen;
75	}
